/** Get cutoffs for a specific phase */
export function getTSPhaseCutoffs(code: string, phaseKey: PhaseKey): YearCutoffs | null {
  const year = phaseKey.split("_")[0];
  let source: Record<string, CollegeCutoffs> | null = null;
  switch (phaseKey) {
    case "2023_phase1": source = TS_CUTOFFS_2023_PHASE1; break;
    case "2023_phase2": source = TS_CUTOFFS_2023_PHASE2; break;
    case "2023_special": source = TS_CUTOFFS_2023_SPECIAL; break;
    case "2022_phase1": source = TS_CUTOFFS_2022_PHASE1; break;
    case "2022_final": source = TS_CUTOFFS_2022_FINAL; break;
    default: return null; // "2024" and "2023" are in ts-cutoffs.ts
  }
  const college = source?.[code];
  if (!college) return null;
  return college[year] || null;
}